UPDATE
MST.TB_TACS_FCLT_MST A
SET

	A.NTACS_FCLT_MST_SEQ = #{ntacsFcltMstSeq, jdbcType=BIGINT}


		, A.NLVL_BAS_SEQ = #{nlvlBasSeq, jdbcType=BIGINT}


		, A.STACS_SERVER_ID = #{stacsServerId, jdbcType=CHAR}


		, A.SFCLT_PROMPT_NM = #{sfcltPromptNm, jdbcType=VARCHAR}


		, A.SFCLT_MODEL_NM = #{sfcltModelNm, jdbcType=VARCHAR}


		, A.SFCLT_TYPE = #{sfcltType, jdbcType=VARCHAR}


		, A.PIP_FCLT_INET = #{pipFcltInet, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		, A.NPORT_FCLT = #{nportFclt, jdbcType=NUMERIC}


		, A.SUSE_YN = #{suseYn, jdbcType=CHAR}


		, A.DCREATE_DT = #{dcreateDt, jdbcType=TIMESTAMP}


		, A.SCREATE_ID = #{screateId, jdbcType=VARCHAR}



		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

		, A.DMODIFY_DT = sysdate

