SELECT , A.RNUM FROM (
	SELECT , ROWNUM RNUM FROM (
		SELECT 
		FROM MST.TB_LVL_BAS A
		, MST.TB_SVC_LINE_TYPE_CD B
		, MST.TB_LVL_CD C
		, MST.TB_LVL_CD D
		, MST.TB_TACS_FCLT_MST E
		WHERE 1=1
		AND A.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003')

			AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}


			AND A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}


			AND A.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}


			AND E.SFCLT_TYPE ILIKE '%' || #{sfcltType, jdbcType=CHAR} || '%'

		AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) 
		AND A.SSVC_GROUP_CD = C.SLVL_CD(+)
		AND A.SSVC_OBJ_CD = D.SLVL_CD(+)
		AND A.NLVL_BAS_SEQ = E.NLVL_BAS_SEQ(+)
		ORDER BY A.SSVC_LINE_TYPE_CD, A.SSVC_GROUP_CD, A.SSVC_OBJ_CD, E.NTACS_FCLT_MST_SEQ
	) A WHERE ROWNUM <= #{lastIndex}
) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM MST.TB_LVL_BAS A , MST.TB_SVC_LINE_TYPE_CD B , MST.TB_LVL_CD C , MST.TB_LVL_CD D , MST.TB_TACS_FCLT_MST E WHERE 1=1 AND A.SSVC_LINE_TYPE_CD IN ('CL0001', 'CL0002', 'CL0003')
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.SSVC_GROUP_CD = #{ssvcGroupCd, jdbcType=CHAR}
AND A.SSVC_OBJ_CD = #{ssvcObjCd, jdbcType=CHAR}
AND E.SFCLT_TYPE ILIKE '%' || #{sfcltType, jdbcType=CHAR} || '%'
AND A.SSVC_LINE_TYPE_CD = B.SSVC_LINE_TYPE_CD(+) AND A.SSVC_GROUP_CD = C.SLVL_CD(+) AND A.SSVC_OBJ_CD = D.SLVL_CD(+) AND A.NLVL_BAS_SEQ = E.NLVL_BAS_SEQ(+)
